PROJECT(face_detection)

include(../dlib/cmake)

set(CMAKE_CXX_FLAGS "${CMAKE_CXX_FLAGS} -Wall -std=gnu++11 -gdwarf-2")

#
# Create python bindings to the code.
#
ADD_SUBDIRECTORY(pybind11)
PYBIND11_ADD_MODULE(pyface pyface.cpp)
TARGET_LINK_LIBRARIES(pyface dlib)
set_target_properties(dlib PROPERTIES POSITION_INDEPENDENT_CODE TRUE)
```

